example.code:
terraform {
  required_providers {
    aws = {}        # RF-03: no version constraint
  }
}

resource "aws_s3_bucket" "logs" {
  acl = "private"   # RF-01: aws_s3_bucket.acl deprecated in v4 provider
}

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.40"
    }
  }
}

resource "aws_s3_bucket" "logs" {
  bucket = "acme-logs-${var.env}"
  tags = {
    owner             = "platform-team"
    environment       = var.env
    cost_center       = "platform"
    data_classification = "internal"
  }
}

resource "aws_s3_bucket_acl" "logs" {
  bucket = aws_s3_bucket.logs.id
  acl    = "private"
}
